{% if avisos_por_treino %}
<div class="mb-3">
    <button type="button" id="abrir-avisos-modal"
            class="inline-flex items-center gap-2 px-3 py-2 rounded-lg text-sm font-semibold border border-amber-300 bg-amber-50 text-amber-800 hover:bg-amber-100">
        <span>⚠️</span>
