cd "g:/My Drive/Projeto Workout App/App Flask HTMX 2" && python -c "
import random
from gerador_treino import carregar_banco, gerar_multiplos_treinos

banco = carregar_banco('banco_exercicios.xlsx')
HIB2 = {'grip': 6, 'lombar': 5, 'core': 6}

cfg = {'demandas': [('regiao', 'lower', 4), ('regiao', 'upper', 3), ('regiao', 'core', 1)], 'tamanho_bloco': 2, 'max_complexidade': 5, 'evitar_agonistas': True}
cfg_on = {**cfg, 'cargas_config': HIB2}

def stats(cfg_, n=1000):
    blocos_solo = 0
    blocos_total = 0
    rotinas_com_relax_carga = 0
    for seed in range(n):
        random.seed(seed)
        sessoes = gerar_multiplos_treinos(banco, [cfg_, cfg_], relaxar_familia=True)
        teve_relax = False
        for s in sessoes:
            for b in s.blocos:
                blocos_total += 1
                exs = [e for e in (b.ex1, b.ex2, b.ex3) if e]
                if len(exs) == 1:
                    blocos_solo += 1
            if any(av['tipo'] == 'relaxado_carga' for av in s.avisos):
                teve_relax = True
        if teve_relax:
            rotinas_com_relax_carga += 1
    return blocos_solo, blocos_total, rotinas_com_relax_carga

solo_off, total_off, rcr_off = stats(cfg)
solo_on, total_on, rcr_on = stats(cfg_on)

print(f'OFF: {solo_off}/{total_off} blocos solo ({solo_off/total_off*100:.2f}%); 0 rotinas com relaxado_carga')
print(f'ON:  {solo_on}/{total_on} blocos solo ({solo_on/total_on*100:.2f}%); {rcr_on}/1000 rotinas com relaxado_carga')
print(f'Diff solo absoluto: {solo_on - solo_off:+d} (+{(solo_on - solo_off)/total_off*100:+.2f}%)')
print(f'Solos forcados por carga (ON-OFF): ~{solo_on - solo_off}')
"
